<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller; use App\Models\ContactMessage; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Illuminate\Support\Facades\Cache; use Illuminate\View\View;
class ContactMessageController extends Controller { public function index(Request $request): View { $messages=ContactMessage::query()->when($request->filled('search'),function($q) use($request){$s='%'.$request->string('search')->toString().'%'; $q->where(function($q)use($s){$q->where('full_name','like',$s)->orWhere('email','like',$s)->orWhere('phone','like',$s)->orWhere('subject','like',$s)->orWhere('message','like',$s);});})->when($request->status==='read',fn($q)=>$q->where('is_read',true))->when($request->status==='unread',fn($q)=>$q->where('is_read',false))->latest()->paginate(15)->withQueryString(); return view('admin.pages.contact-messages.index',compact('messages')); } public function show(ContactMessage $contactMessage): View { return view('admin.pages.contact-messages.show',['message'=>$contactMessage]); } public function markRead(ContactMessage $contactMessage): RedirectResponse { $contactMessage->update(['is_read'=>true]); Cache::forget('contact_messages_unread_count'); return back()->with('success','Message marked as read.'); } public function markUnread(ContactMessage $contactMessage): RedirectResponse { $contactMessage->update(['is_read'=>false]); Cache::forget('contact_messages_unread_count'); return back()->with('success','Message marked as unread.'); } public function destroy(ContactMessage $contactMessage): RedirectResponse { $contactMessage->delete(); Cache::forget('contact_messages_unread_count'); return redirect()->route('admin.contact-messages.index')->with('success','Message deleted successfully.'); } }
